const staticData = $getWorkflowStaticData('global');
if (!staticData.processedIds) {
  staticData.processedIds = [];
}

const response = $input.first().json;
const notifications = response?.data?.notifications?.data || [];

const projectNotifications = notifications.filter((n) => {
  const url = n.url || n.link || '';
  return url.includes('klnc.ir') || url.includes('/projects/');
});

const newNotifications = projectNotifications.filter((n) => {
  const id = String(n.id || n.url || n.link);
  return !staticData.processedIds.includes(id);
});

if (newNotifications.length === 0) {
  return [];
}

return newNotifications.map((notification) => {
  const url = notification.url || notification.link || '';
  const shortCode = url.split('/').pop().split('?')[0];

  return {
    json: {
      notificationId: String(notification.id || url),
      shortCode,
      notificationTitle: notification.title || notification.subject || '',
      notificationBody: notification.body || notification.message || '',
      notificationTime: notification.created_at || notification.createdAt || ''
    }
  };
});

const items = $input.all();
const results = [];

const extractProject = (html, meta = {}) => {
  const titleMatch = html.match(/<h1[^>]*class="[^"]*fs-18[^"]*font-weight-bold[^"]*"[^>]*>([^<]*)<\/h1>/);
  const title = titleMatch ? titleMatch[1].trim() : meta.notificationTitle || 'نامشخص';

  const budgetMatch = html.match(/از\s*([\d,]+)\s*تومان[\s\S]*?تا\s*([\d,]+)\s*تومان/);
  let minBudget = null;
  let maxBudget = null;
  if (budgetMatch) {
    minBudget = parseInt(budgetMatch[1].replace(/,/g, ''), 10);
    maxBudget = parseInt(budgetMatch[2].replace(/,/g, ''), 10);
  }

  const locationMatch = html.match(/<i[^>]*class="[^"]*icon-location[^"]*"[^>]*><\/i>\s*([^<]*)/);
  const location = locationMatch ? locationMatch[1].trim() : '';

  const timeMatch = html.match(/<span[^>]*class="[^"]*bg-39-color[^"]*"[^>]*>([^<]*)<\/span>/);
  const postedTime = timeMatch ? timeMatch[1].trim() : '';

  const durationMatch = html.match(/زمان پیشنهادی\s*<div[^>]*class="[^"]*fs-16[^"]*b-900[^"]*"[^>]*>([^<]*)<\/div>/);
  const jobDuration = durationMatch ? durationMatch[1].replace(/[^0-9]/g, '') : '';

  const descMatch = html.match(/<div[^>]*class="[^"]*white-space-pre-line[^"]*"[^>]*>([^<]*)<\/div>/);
  const description = descMatch ? descMatch[1].trim().replace(/\s+/g, ' ') : meta.notificationBody || '';

  const skillMatches = html.match(/<span[^>]*class="[^"]*ellipsis[^"]*"[^>]*>([^<]*)<\/span>/g);
  let skills = [];
  if (skillMatches) {
    skills = skillMatches
      .map((s) => {
        const match = s.match(/>([^<]*)</);
        return match ? match[1].trim() : '';
      })
      .filter((s) => s && !s.includes('کارلنسر') && s.length > 1);
  }

  const statusMatch = html.match(/وضعیت\s*<div[^>]*class="[^"]*fs-16[^"]*b-900[^"]*"[^>]*>([^<]*)<\/div>/);
  const status = statusMatch ? statusMatch[1].trim() : '';

  const urlMatch = html.match(/\/projects\/([^"'?#]+)/);
  const projectSlug = urlMatch ? urlMatch[1] : '';
  const projectLink = projectSlug
    ? `https://www.karlancer.com/projects/${projectSlug}`
    : `https://klnc.ir/l/${meta.shortCode}`;

  return {
    notification_id: meta.notificationId,
    short_code: meta.shortCode,
    title,
    min_budget: minBudget,
    max_budget: maxBudget,
    budget_range:
      minBudget && maxBudget
        ? `${minBudget.toLocaleString()} تا ${maxBudget.toLocaleString()} تومان`
        : '',
    location,
    posted_time: postedTime,
    job_duration_days: jobDuration,
    description,
    skills,
    status,
    project_url: projectLink,
    notification_time: meta.notificationTime,
    extracted_at: new Date().toISOString()
  };
};

for (const item of items) {
  const meta = {
    notificationId: item.json.notificationId,
    shortCode: item.json.shortCode,
    notificationTitle: item.json.notificationTitle,
    notificationBody: item.json.notificationBody,
    notificationTime: item.json.notificationTime
  };

  const htmlData = item.json.data || item.json;
  let htmlContent = '';

  if (typeof htmlData === 'string') {
    htmlContent = htmlData;
  } else if (Array.isArray(htmlData)) {
    htmlContent = htmlData.map((h) => h.data || h).join('');
  } else {
    htmlContent = htmlData.data || JSON.stringify(htmlData);
  }

  results.push({ json: extractProject(htmlContent, meta) });
}

return results;

const projects = $input.all().map((item) => item.json);

if (!projects.length) {
  return [];
}

return projects.map((p) => {
  let message = '🆕 *پروژه جدید از نوتیفیکیشن کارلنسر*\n\n';
  message += `📌 *عنوان:* ${p.title || 'نامشخص'}\n`;

  if (p.min_budget || p.max_budget) {
    const min = p.min_budget ? p.min_budget.toLocaleString() : 'نامشخص';
    const max = p.max_budget ? p.max_budget.toLocaleString() : 'نامشخص';
    message += `💰 *بودجه:* ${min} تا ${max} تومان\n`;
  } else if (p.budget_range) {
    message += `💰 *بودجه:* ${p.budget_range}\n`;
  }

  if (p.location) message += `📍 *مکان:* ${p.location}\n`;
  if (p.posted_time) message += `⏰ *زمان انتشار:* ${p.posted_time}\n`;
  if (p.job_duration_days) message += `📅 *مدت زمان:* ${p.job_duration_days} روز\n`;
  if (p.status) message += `📊 *وضعیت:* ${p.status}\n`;

  if (p.skills && p.skills.length) {
    const skillList = p.skills.slice(0, 5).join(' • ');
    message += `🛠 *مهارت‌ها:* ${skillList}`;
    if (p.skills.length > 5) message += ` و ${p.skills.length - 5} مورد دیگر`;
    message += '\n';
  }

  if (p.description) {
    const desc = p.description.length > 300 ? `${p.description.substring(0, 300)}...` : p.description;
    message += `📝 *توضیحات:* ${desc}\n`;
  }

  message += `🔗 *لینک پروژه:* ${p.project_url}\n`;
  message += `🕐 *زمان استخراج:* ${new Date(p.extracted_at).toLocaleString('fa-IR')}\n`;
  message += '\n🤖 _ارسال شده توسط ربات کارلنسر_';

  return {
    json: {
      message,
      notification_id: p.notification_id
    }
  };
});

const staticData = $getWorkflowStaticData('global');
if (!staticData.processedIds) {
  staticData.processedIds = [];
}

const sentItems = $('Format Telegram Message').all();

for (const item of sentItems) {
  const id = String(item.json.notification_id);
  if (id && !staticData.processedIds.includes(id)) {
    staticData.processedIds.push(id);
  }
}

if (staticData.processedIds.length > 500) {
  staticData.processedIds = staticData.processedIds.slice(-500);
}

return sentItems;
